const path = require('path');

const LIB = require('../lib/jibo-cai-utils');
const TimeUtils = LIB.TimeUtils;
const SessionManager = LIB.SessionManager;
const Session = LIB.Session;

class FakeSkill {

	constructor() {
		this.session = new SessionManager(
			(options) => {
				return {
					promise: this._createRunPromise(),
					stop: () => {}
				}
			},
			() => this.exit()
		)

		this._createRunPromiseSpy = sinon.spy(this, '_createRunPromise');
		this.exitSpy = sinon.spy(this, 'exit');
	}

	_createRunPromise(options) {
		return TimeUtils.wait(10);
	}

	open(options) {
		this.session.open(options);
	}

	refresh(options) {
		this.session.replaceSession(options);
	}

	close(done) {
		this.session.close()
			.then(() => done())
			.catch(done);
	}

	exit() { }
}

function createFakeSkill() {
	return
}

describe('SessionManager', () => {

	it('Regular one time run of skill', () => {
		let skill = new FakeSkill();
		skill.open({});
		expect(skill._createRunPromiseSpy.callCount).to.equal(1);
		return skill.session.waitForCurrent().then(() => {
			expect(skill._createRunPromiseSpy.callCount).to.equal(1);
			expect(skill.exitSpy.callCount).to.equal(1);
		});
	});

	it('Refresh called mid-skill', () => {
		let skill = new FakeSkill();
		skill.open({});
		skill.refresh({})

		const pr1 = skill.session.waitForCurrent().then(() => {
			expect(skill._createRunPromiseSpy.callCount).to.equal(2);
			expect(skill.exitSpy.callCount).to.equal(0);
		});

		const pr2 = skill.session.waitForAll().then(() => {
			expect(skill._createRunPromiseSpy.callCount).to.equal(2);
			expect(skill.exitSpy.callCount).to.equal(1);
		});

		return Promise.all([pr1, pr2]);
	});

	it('Close and open called mid-skill', (done) => {
		let skill = new FakeSkill();

		skill.open({});
		skill.close(() => {
			skill.open({});
			skill.close(() => {
				skill.open({});
				skill.session.waitForAll().then(() => {
					expect(skill._createRunPromiseSpy.callCount).to.equal(3);
					expect(skill.exitSpy.callCount).to.equal(1);
					done();
				});
			});
		});
	});

});

describe('Session', () => {

	it('Should construct properly', () => {
		const session = new Session();
		expect(typeof session.id).to.equal('string');
		expect(session.active).to.equal(false);
		expect(session.hasBeenStopped).to.equal(false);
	});
});